// To prove: ∀x ∈ D, P(x)
// Method: Universal Generalization

FUNCTION proveUniversal(D, P):
 // Step 1: Choose arbitrary element
 LET a ← arbitrary element from D

 // Step 2: Prove P(a) holds for this arbitrary a
 PROOF OF P(a):
 // Use properties of a and definitions
 // ... proof steps ...
 END PROOF

 // Step 3: Universal Generalization
 // Since a was arbitrary, P holds for all x ∈ D
 RETURN TRUE // Hence ∀x ∈ D, P(x) is proved

// To prove: ∃x ∈ D, P(x)
// Method: Find a witness

FUNCTION proveExistential(D, P):
 // Step 1: Find a specific element c ∈ D
 // This may require construction or insight

 IF findWitness(D, P) = TRUE THEN:
 c ← the witness element
 // Step 2: Verify P(c) is true
 VERIFY P(c):
 // Show specifically that c satisfies P
 // ... verification steps ...
 END VERIFY

 // Step 3: Conclude existence
 RETURN TRUE // Hence ∃x ∈ D, P(x) is proved
 ELSE:
 RETURN FALSE // No witness exists
 END IF

// Negation rules for quantifiers
// Rule 1: ¬∀x P(x) ≡ ∃x ¬P(x)
// Rule 2: ¬∃x P(x) ≡ ∀x ¬P(x)

FUNCTION negateUniversal(PredicateFunction):
 // Input: Predicate P(x) as a function
 // Output: Equivalent negated form

 original ← "∀x P(x)"
 negated ← "∃x ¬P(x)"
 RETURN negated

FUNCTION negateExistential(PredicateFunction):
 // Input: Predicate P(x) as a function
 // Output: Equivalent negated form

 original ← "∃x P(x)"
 negated ← "∀x ¬P(x)"
 RETURN negated

